/* ─────────────────────────────────────────
   HOOK: scroll progress of an element
───────────────────────────────────────── */
function useScrollProgress(ref) {
  const [progress, setProgress] = useState(0);
  useEffect(() => {
    const onScroll = () => {
      if (!ref.current) return;
      const rect = ref.current.getBoundingClientRect();
      const vh   = window.innerHeight;
      // 0 = element top at bottom of screen, 1 = element bottom at top
      const p = 1 - (rect.bottom / (vh + rect.height));
      setProgress(Math.min(1, Math.max(0, p)));
    };
    window.addEventListener('scroll', onScroll, { passive: true });
    onScroll();
    return () => window.removeEventListener('scroll', onScroll);
  }, []);
  return progress;
}

/* ─────────────────────────────────────────
   COMPONENT: Split-text reveal on scroll
───────────────────────────────────────── */
function SplitReveal({ text, color, style = {} }) {
  const ref  = useRef(null);
  const [vis, setVis] = useState(false);
  useEffect(() => {
    const io = new IntersectionObserver(([e]) => { if (e.isIntersecting) setVis(true); }, { threshold: 0.3 });
    if (ref.current) io.observe(ref.current);
    return () => io.disconnect();
  }, []);
  const words = text.split('\n').map(line => line.split(' '));
  let wordIdx = 0;
  return (
    <div ref={ref} style={{ overflow: 'hidden', ...style }}>
      {words.map((line, li) => (
        <div key={li} style={{ display: 'block' }}>
          {line.map((word) => {
            const delay = wordIdx++ * 0.07;
            return (
              <span key={word + delay} style={{
                display: 'inline-block', marginRight: '0.32em',
                transform: vis ? 'translateY(0)' : 'translateY(110%)',
                opacity: vis ? 1 : 0,
                transition: `transform 0.7s cubic-bezier(0.16,1,0.3,1) ${delay}s, opacity 0.5s ease ${delay}s`,
                color: word === word ? undefined : color,
              }}>{word}</span>
            );
          })}
        </div>
      ))}
    </div>
  );
}

/* ─────────────────────────────────────────
   COMPONENT: Staggered list items
───────────────────────────────────────── */
function StaggerList({ items, color, renderItem, delay = 0 }) {
  const ref  = useRef(null);
  const [vis, setVis] = useState(false);
  useEffect(() => {
    const io = new IntersectionObserver(([e]) => { if (e.isIntersecting) setVis(true); }, { threshold: 0.15 });
    if (ref.current) io.observe(ref.current);
    return () => io.disconnect();
  }, []);
  return (
    <div ref={ref}>
      {items.map((item, i) => (
        <div key={i} style={{
          opacity: vis ? 1 : 0,
          transform: vis ? 'translateX(0)' : 'translateX(-24px)',
          transition: `all 0.55s cubic-bezier(0.16,1,0.3,1) ${delay + i * 0.08}s`,
        }}>
          {renderItem(item, i)}
        </div>
      ))}
    </div>
  );
}

/* ─────────────────────────────────────────
   COMPONENT: Horizontal Scroll Progress Bar
───────────────────────────────────────── */
function ScrollProgressBar({ color }) {
  const [pct, setPct] = useState(0);
  useEffect(() => {
    const onScroll = () => {
      const doc  = document.documentElement;
      const scrolled = doc.scrollTop;
      const total    = doc.scrollHeight - doc.clientHeight;
      setPct(total ? (scrolled / total) * 100 : 0);
    };
    window.addEventListener('scroll', onScroll, { passive: true });
    return () => window.removeEventListener('scroll', onScroll);
  }, []);
  return (
    <div style={{ position: 'fixed', top: 0, left: 0, right: 0, height: 3, zIndex: 9999, background: 'rgba(0,0,0,0.08)' }}>
      <div style={{ height: '100%', width: `${pct}%`, background: color, transition: 'width 0.1s linear', boxShadow: `0 0 8px ${color}` }} />
    </div>
  );
}

