/* ─────────────────────────────────────────
   COMPONENT: One service panel
   Effect: sticky image + scroll-clipped content
───────────────────────────────────────── */
function ServicePanel({ svc, index, onVisible }) {
  const panelRef  = useRef(null);
  const imgRef    = useRef(null);
  const [entered, setEntered] = useState(false);
  const [imgScale, setImgScale] = useState(1.15);
  const [clipPct, setClipPct]   = useState(100);
  const [labelY, setLabelY]     = useState(60);
  const isEven = index % 2 === 0;

  useEffect(() => {
    const io = new IntersectionObserver(([e]) => {
      if (e.isIntersecting) { setEntered(true); onVisible(index); }
    }, { threshold: 0.25 });
    if (panelRef.current) io.observe(panelRef.current);

    const onScroll = () => {
      if (!panelRef.current) return;
      const rect = panelRef.current.getBoundingClientRect();
      const vh   = window.innerHeight;
      // How far section has scrolled into view (0→1)
      const enter = Math.min(1, Math.max(0, 1 - rect.top / vh));
      // Image: subtle parallax scale
      const scale = 1.15 - enter * 0.08;
      setImgScale(Math.max(1.04, scale));
      // Content clip: wipe up from bottom
      const clip = Math.max(0, 100 - enter * 110);
      setClipPct(clip);
      // Label floating up
      setLabelY(Math.max(0, 60 - enter * 65));
    };
    window.addEventListener('scroll', onScroll, { passive: true });
    onScroll();
    return () => { io.disconnect(); window.removeEventListener('scroll', onScroll); };
  }, [index, onVisible]);

  return (
    <section
      ref={panelRef}
      id={svc.id}
      style={{
        display: 'grid',
        gridTemplateColumns: '1fr',
        minHeight: '100vh',
        borderTop: '1px solid rgba(0,0,0,0.07)',
        overflow: 'hidden',
        position: 'relative',
