              </a>
            ))}
          </div>

          {/* Scroll cue */}
          <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 8, opacity: 0.4, animation: 'fadeIn 1s 1.2s both' }}>
            <span style={{ fontSize: '0.62rem', color: '#fff', letterSpacing: '0.2em', textTransform: 'uppercase' }}>Scroll to explore</span>
            <div style={{ width: 1, height: 36, background: 'linear-gradient(to bottom,#fff,transparent)', animation: 'scrollLine 2s ease-in-out infinite' }} />
            <ChevronDown size={14} color="#fff" />
          </div>
        </div>
      </section>

      {/* ════════════════════════════════════════
          SERVICE PANELS — clip-wipe + parallax
      ════════════════════════════════════════ */}
      {SVCS.map((svc, idx) => (
        <ServicePanel key={svc.id} svc={svc} index={idx} onVisible={handleVisible} />
      ))}

      {/* ════════════════════════════════════════
          CTA
      ════════════════════════════════════════ */}
      <section style={{ background: '#060c18', position: 'relative', overflow: 'hidden' }}>
        <img src="https://images.unsplash.com/photo-1551434678-e076c223a692?w=1600&q=75"
          alt="" aria-hidden style={{ position: 'absolute', inset: 0, width: '100%', height: '100%', objectFit: 'cover', opacity: .07 }} />
        <div style={{ position: 'absolute', inset: 0, background: 'rgba(6,12,24,0.96)' }} />
        <div style={{
          position: 'absolute', top: '50%', left: '50%', transform: 'translate(-50%,-50%)',
          width: 600, height: 600,
          background: `radial-gradient(circle, rgba(0,87,255,0.08) 0%, transparent 70%)`,
          pointerEvents: 'none',
        }}/>
        <div className="wrap" style={{ padding: '96px 20px', position: 'relative', zIndex: 1, textAlign: 'center' }}>
          <span style={{ fontSize: '0.68rem', fontWeight: 700, letterSpacing: '0.18em', textTransform: 'uppercase', color: 'rgba(255,255,255,0.35)', display: 'block', marginBottom: 16 }}>Ready to Build?</span>
          <h2 style={{ fontFamily: 'var(--serif)', fontSize: 'clamp(2rem,4.5vw,3.5rem)', fontWeight: 800, color: '#fff', marginBottom: 16, letterSpacing: '-0.025em', lineHeight: 1.1 }}>
            Have a Project in Mind?
          </h2>
          <p style={{ fontSize: '1rem', color: 'rgba(255,255,255,0.5)', lineHeight: 1.85, maxWidth: 460, margin: '0 auto 36px' }}>
            Tell us about your idea and we'll build a tailored plan — on time, within budget, beyond expectations.
          </p>
          <Link to="/contact" style={{
            display: 'inline-flex', alignItems: 'center', gap: 9,
            padding: '15px 32px', borderRadius: 12,
            background: '#fff', color: '#040b18',
            fontSize: '0.92rem', fontWeight: 800,
            boxShadow: '0 4px 24px rgba(255,255,255,0.12)',
            transition: 'all 0.25s ease',
          }}
            onMouseEnter={e => { e.currentTarget.style.background = '#0057ff'; e.currentTarget.style.color = '#fff'; e.currentTarget.style.transform = 'translateY(-3px)'; e.currentTarget.style.boxShadow = '0 10px 30px rgba(0,87,255,0.5)'; }}
            onMouseLeave={e => { e.currentTarget.style.background = '#fff'; e.currentTarget.style.color = '#040b18'; e.currentTarget.style.transform = 'translateY(0)'; e.currentTarget.style.boxShadow = '0 4px 24px rgba(255,255,255,0.12)'; }}
          >
            Get a Free Consultation <ArrowRight size={16} />
          </Link>
        </div>
      </section>

      {/* ─── Global Keyframes ─── */}
      <style>{`
        @media (min-width: 768px) {
          .svc-panel       { grid-template-columns: 1fr 1fr !important; }
          .svc-img-half    { min-height: unset !important; }
          .svc-content-half{ min-height: 100vh !important; }
        }
        @media (max-width: 767px) {
          .svc-img-half    { min-height: 280px !important; order: 1 !important; }
          .svc-content-half{ order: 2 !important; clip-path: none !important; }
        }
        @keyframes wordRise {
          from { opacity: 0; transform: translateY(60px) rotate(2deg); }
          to   { opacity: 1; transform: translateY(0) rotate(0deg); }
        }
        @keyframes fadeSlideDown {
          from { opacity: 0; transform: translateY(-18px); }
          to   { opacity: 1; transform: translateY(0); }
        }
        @keyframes fadeIn {
          from { opacity: 0; } to { opacity: 0.4; }
        }
        @keyframes ringPulse {
          0%,100% { opacity: 0.4; transform: translate(-50%,-50%) scale(1); }
          50%      { opacity: 0.9; transform: translate(-50%,-50%) scale(1.04); }
        }
        @keyframes glow {
          0%,100% { box-shadow: 0 0 6px #4ade80; }
          50%      { box-shadow: 0 0 14px #4ade80, 0 0 28px #4ade8066; }
        }
        @keyframes scrollLine {
          0%,100% { opacity: 0; transform: scaleY(0); transform-origin: top; }
          50%      { opacity: 1; transform: scaleY(1); }
        }
      `}</style>
    </div>
  );
}
